import StripePaymentSheet

class ViewController: UIViewController {

    private var mapView: GMSMapView!
    private var paymentButton: UIButton!

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .white
        setupMapView()
        setupPaymentButton()
    }

    private func setupMapView() {
        // Create a camera position
        let camera = GMSCameraPosition.camera(withLatitude: 34.052235, longitude: -118.243683, zoom: 12.0) // Downtown LA
        mapView = GMSMapView.map(withFrame: .zero, camera: camera)
        mapView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(mapView)

        // Add a marker
        let marker = GMSMarker()
        marker.position = CLLocationCoordinate2D(latitude: 34.052235, longitude: -118.243683)
        marker.title = "Los Angeles"
        marker.snippet = "Demo Location"
        marker.map = mapView

        NSLayoutConstraint.activate([
            mapView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            mapView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            mapView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            mapView.heightAnchor.constraint(equalTo: view.heightAnchor, multiplier: 0.7) // Map takes 70% of the screen
        ])
    }

    private func setupPaymentButton() {
